export interface CSVParseOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Array<Record<string, any>>;
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: Record<string, any>) => boolean): Record<string, any>[];
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<any, Record<string, any>[]>;
}

function coerceValue(value: string | null): any {
  if (value === null) return null;
  const trimmed = value.trim();
  if (trimmed === "" || trimmed.toLowerCase() === "null") return null;
  const lower = trimmed.toLowerCase();
  if (lower === "true") return true;
  if (lower === "false") return false;
  const num = Number(trimmed);
  if (!Number.isNaN(num) && trimmed !== "") return num;
  return value;
}

function splitCSVRows(input: string, lineSeparator: string): string[] {
  return input.split(lineSeparator);
}

function parseLine(line: string, delimiter: string, quote: string): { fields: string[]; error?: string } {
  const fields: string[] = [];
  let current = "";
  let inQuotes = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (ch === quote) {
      if (inQuotes && line[i + 1] === quote) {
        current += quote;
        i++;
      } else {
        inQuotes = !inQuotes;
      }
    } else if (ch === delimiter && !inQuotes) {
      fields.push(current);
      current = "";
    } else {
      current += ch;
    }
  }
  if (inQuotes) {
    return { fields, error: "Unclosed quote" };
  }
  fields.push(current);
  return { fields };
}

export function parseCSV(input: string, options: CSVParseOptions = {}): CSVResult {
  const delimiter = options.delimiter ?? ",";
  const quote = options.quote ?? '"';
  const lineSeparator = options.lineSeparator ?? "\n";

  const rows: Array<Record<string, any>> = [];
  const errors: CSVError[] = [];

  if (!input) {
    return createResult(rows, [], errors);
  }

  const lines = splitCSVRows(input, lineSeparator).filter((line) => line !== "");
  if (lines.length === 0) return createResult(rows, [], errors);

  const headerParse = parseLine(lines[0], delimiter, quote);
  const headers = headerParse.fields.map((h) => h.trim());
  if (headerParse.error) {
    errors.push({ row: 1, message: headerParse.error });
  }

  for (let i = 1; i < lines.length; i++) {
    const line = lines[i];
    const parsed = parseLine(line, delimiter, quote);
    if (parsed.error) {
      errors.push({ row: i + 1, message: parsed.error });
      continue;
    }
    if (parsed.fields.length !== headers.length) {
      errors.push({ row: i + 1, message: "Column count does not match headers" });
      continue;
    }
    const row: Record<string, any> = {};
    for (let j = 0; j < headers.length; j++) {
      row[headers[j]] = coerceValue(parsed.fields[j]);
    }
    rows.push(row);
  }

  return createResult(rows, headers, errors);
}

function createResult(
  rows: Array<Record<string, any>>,
  headers: string[],
  errors: CSVError[]
): CSVResult {
  return {
    rows,
    headers,
    errors,
    filter(predicate: (row: Record<string, any>) => boolean) {
      return rows.filter(predicate);
    },
    sum(column: string) {
      return rows.reduce((acc, row) => {
        const val = row[column];
        return typeof val === "number" && !Number.isNaN(val) ? acc + val : acc;
      }, 0);
    },
    average(column: string) {
      let total = 0;
      let count = 0;
      for (const row of rows) {
        const val = row[column];
        if (typeof val === "number" && !Number.isNaN(val)) {
          total += val;
          count++;
        }
      }
      return count === 0 ? 0 : total / count;
    },
    count() {
      return rows.length;
    },
    groupBy(column: string) {
      const map = new Map<any, Record<string, any>[]>();
      for (const row of rows) {
        const key = row[column];
        if (!map.has(key)) map.set(key, []);
        map.get(key)!.push(row);
      }
      return map;
    },
  };
}

import { parseCSV } from "./csv-parser";

function assert(condition: any, message: string) {
  if (!condition) throw new Error(message);
}

// basic parsing
{
  const input = "name,age\nAlice,30\nBob,25";
  const result = parseCSV(input);
  assert(result.rows.length === 2, "basic parsing rows count");
  assert(result.rows[0].name === "Alice", "basic parsing name");
  assert(result.rows[0].age === 30, "basic parsing age");
}

// quoted fields with commas
{
  const input = "name,notes\nAlice,\"loves, commas\"";
  const result = parseCSV(input);
  assert(result.rows[0].notes === "loves, commas", "quoted fields with commas");
}

// escaped quotes
{
  const input = "quote\n\"He said \"\"hello\"\"\"";
  const result = parseCSV(input);
  assert(result.rows[0].quote === "He said \"hello\"", "escaped quotes");
}

// custom delimiters
{
  const input = "a|b|c\n1|2|3";
  const result = parseCSV(input, { delimiter: "|" });
  assert(result.rows[0].b === 2, "custom delimiter");
}

// type coercion for all types
{
  const input = "n1,n2,b1,b2,null1,null2,str\n10,3.14,true,FALSE,null,,hello";
  const result = parseCSV(input);
  const row = result.rows[0];
  assert(row.n1 === 10, "int coercion");
  assert(row.n2 === 3.14, "float coercion");
  assert(row.b1 === true, "bool true coercion");
  assert(row.b2 === false, "bool false coercion");
  assert(row.null1 === null, "null coercion");
  assert(row.null2 === null, "empty string to null");
  assert(row.str === "hello", "string stays string");
}

// malformed row error collection
{
  const input = "a,b\n1,2\n3";
  const result = parseCSV(input);
  assert(result.errors.length === 1, "malformed row error count");
  assert(result.errors[0].row === 3, "malformed row error row number");
}

// filter functionality
{
  const input = "name,age\nAlice,30\nBob,25\nCara,35";
  const result = parseCSV(input);
  const filtered = result.filter((r) => r.age > 30);
  assert(filtered.length === 1 && filtered[0].name === "Cara", "filter functionality");
}

// aggregation methods
{
  const input = "name,score,group\nA,10,x\nB,20,x\nC,30,y";
  const result = parseCSV(input);
  assert(result.count() === 3, "count");
  assert(result.sum("score") === 60, "sum");
  assert(result.average("score") === 20, "average");
  const grouped = result.groupBy("group");
  assert(grouped.get("x")!.length === 2, "groupBy x");
  assert(grouped.get("y")!.length === 1, "groupBy y");
}

// edge cases: empty input
{
  const result = parseCSV("");
  assert(result.rows.length === 0, "empty input rows");
  assert(result.headers.length === 0, "empty input headers");
}

// edge cases: single column, single row
{
  const input = "only\nvalue";
  const result = parseCSV(input);
  assert(result.rows.length === 1, "single row length");
  assert(result.rows[0].only === "value", "single column value");
}

// edge cases: very large fields
{
  const large = "x".repeat(10000);
  const input = "field\n\"" + large + "\"";
  const result = parseCSV(input);
  assert(result.rows[0].field === large, "large field parsing");
}

console.log("All tests passed.");

